  1	import React, { FC } from 'react';
  2	
  3	import { Alert, AlertVariant, Button, Flex, FlexItem, PageSection, Text, Title } from '@patternfly/react-core';
  4	import { useTranslation } from 'react-i18next';
  5	import { flowCollectorEditPath, flowCollectorNewPath, netflowTrafficPath, useNavigate } from '../../utils/url';
  6	import './forms.css';
  7	import { Pipeline } from './pipeline';
  8	import { ResourceStatus } from './resource-status';
  9	import { Consumer, ResourceWatcher } from './resource-watcher';
 10	
 11	export type FlowCollectorStatusProps = {};
 12	
 13	export const FlowCollectorStatus: FC<FlowCollectorStatusProps> = () => {
 14	  const { t } = useTranslation('plugin__netobserv-plugin');
 15	  const navigate = useNavigate();
 16	  const [selectedTypes, setSelectedTypes] = React.useState<string[]>([]);
 17	
 18	  return (
 19	    <ResourceWatcher
 20	      group="flows.netobserv.io"
 21	      version="v1beta2"
 22	      kind="FlowCollector"
 23	      name="cluster"
 24	      skipErrors
 25	      defaultFrom="None"
 26	    >
 27	      <Consumer>
 28	        {ctx => {
 29	          // Check if operator is in hold mode
 30	          const isOnHold = ctx.data?.spec?.execution?.mode === 'OnHold';
 31	
 32	          return (
 33	            <PageSection id="pageSection">
 34	              <div id="pageHeader">
 35	                <Title headingLevel="h1" size="2xl">
 36	                  {t('Network Observability FlowCollector status')}
 37	                </Title>
 38	              </div>
 39	              {ctx.data && (
 40	                <Flex className="status-container" direction={{ default: 'column' }}>
 41	                  <FlexItem flex={{ default: 'flex_1' }}>
 42	                    {isOnHold ? (
 43	                      <Alert variant={AlertVariant.info} isInline title={t('Network Observability is on hold')}>
 44	                        {t(
 45	                          // eslint-disable-next-line max-len
 46	                          'Execution mode is set to OnHold. All operator-managed workloads have been deleted, while preserving other resources. To change execution mode, update or remove "spec.execution.mode" in the FlowCollector resource.'
 47	                        )}
 48	                      </Alert>
 49	                    ) : (
 50	                      <Pipeline existing={ctx.data} selectedTypes={selectedTypes} setSelectedTypes={setSelectedTypes} />
 51	                    )}
 52	                  </FlexItem>
 53	                  <FlexItem className="status-list-container" flex={{ default: 'flex_1' }}>
 54	                    <ResourceStatus
 55	                      group={ctx.group}
 56	                      version={ctx.version}
 57	                      kind={ctx.kind}
 58	                      existing={ctx.data}
 59	                      selectedTypes={selectedTypes}
 60	                      setSelectedTypes={setSelectedTypes}
 61	                    />
 62	                  </FlexItem>
 63	                  <FlexItem>
 64	                    <Flex>
 65	                      <FlexItem>
 66	                        <Button
 67	                          id="edit-flow-collector"
 68	                          data-test-id="edit-flow-collector"
 69	                          variant="primary"
 70	                          onClick={() => navigate(flowCollectorEditPath)}
 71	                        >
 72	                          {t('Edit FlowCollector')}
 73	                        </Button>
 74	                      </FlexItem>
 75	                      {!isOnHold && (
 76	                        <FlexItem>
 77	                          <Button
 78	                            id="open-network-traffic"
 79	                            data-test-id="open-network-traffic"
 80	                            variant="link"
 81	                            onClick={() => navigate(netflowTrafficPath)}
 82	                          >
 83	                            {t('Open Network Traffic page')}
 84	                          </Button>
 85	                        </FlexItem>
 86	                      )}
 87	                    </Flex>
 88	                  </FlexItem>
 89	                </Flex>
 90	              )}
 91	              {ctx.loadError && (
 92	                <Flex direction={{ default: 'column' }}>
 93	                  <FlexItem>
 94	                    <Text>
 95	                      {t('An error occured while retreiving FlowCollector: {{error}}', { error: ctx.loadError })}
 96	                    </Text>
 97	                  </FlexItem>
 98	                  <FlexItem alignSelf={{ default: 'alignSelfCenter' }}>
 99	                    <Button id="create-flow-collector" onClick={() => navigate(flowCollectorNewPath)}>
100	                      {t('Create FlowCollector')}
101	                    </Button>
102	                  </FlexItem>
103	                </Flex>
104	              )}
105	            </PageSection>
106	          );
107	        }}
108	      </Consumer>
109	    </ResourceWatcher>
110	  );
111	};
112	
113	export default FlowCollectorStatus;

